import{_ as t,o as i,c as a,a0 as s}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"AnimeTV Build & Release Guide (Windows & Android)","description":"","frontmatter":{},"headers":[],"relativePath":"WINDOWS_BUILD_GUIDE.md","filePath":"WINDOWS_BUILD_GUIDE.md"}'),l={name:"WINDOWS_BUILD_GUIDE.md"};function n(o,e,d,r,p,h){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="animetv-build-release-guide-windows-android" tabindex="-1">AnimeTV Build &amp; Release Guide (Windows &amp; Android) <a class="header-anchor" href="#animetv-build-release-guide-windows-android" aria-label="Permalink to &quot;AnimeTV Build &amp; Release Guide (Windows &amp; Android)&quot;">​</a></h1><p>This guide provides step-by-step instructions on how to build, package, and test both the <strong>Windows Desktop</strong> and <strong>Android TV / Google TV</strong> versions of AnimeTV.</p><hr><h2 id="📋-prerequisites" tabindex="-1">📋 Prerequisites <a class="header-anchor" href="#📋-prerequisites" aria-label="Permalink to &quot;📋 Prerequisites&quot;">​</a></h2><p>Before running any build commands, ensure your machine has the following tools installed and configured:</p><h3 id="for-both-builds" tabindex="-1">For Both Builds <a class="header-anchor" href="#for-both-builds" aria-label="Permalink to &quot;For Both Builds&quot;">​</a></h3><ol><li><strong>Node.js &amp; npm</strong> (v18+ recommended)</li><li><strong>Git</strong></li><li><strong>PowerShell</strong> or any Windows-compatible terminal.</li></ol><h3 id="for-android-builds-only" tabindex="-1">For Android Builds Only <a class="header-anchor" href="#for-android-builds-only" aria-label="Permalink to &quot;For Android Builds Only&quot;">​</a></h3><ol><li><strong>Java JDK</strong> (JDK 17 recommended for modern Android Gradle builds).</li><li><strong>Android SDK Command-Line Tools</strong> (or <strong>Android Studio</strong> which bundles the SDK and emulators).</li><li><strong>ADB (Android Debug Bridge)</strong> (for deploying and testing directly on a connected TV, phone, or emulator).</li></ol><hr><h2 id="⚙️-initial-setup" tabindex="-1">⚙️ Initial Setup <a class="header-anchor" href="#⚙️-initial-setup" aria-label="Permalink to &quot;⚙️ Initial Setup&quot;">​</a></h2><p>To prepare the repository and install all required Node modules, run the following command from the project root:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install</span></span></code></pre></div><h3 id="step-0-compile-frontend-assets-required-for-both-windows-android" tabindex="-1">Step 0: Compile Frontend Assets (Required for both Windows &amp; Android) <a class="header-anchor" href="#step-0-compile-frontend-assets-required-for-both-windows-android" aria-label="Permalink to &quot;Step 0: Compile Frontend Assets (Required for both Windows &amp; Android)&quot;">​</a></h3><p>AnimeTV is a hybrid application. Its core UI and logic must be compiled first:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run build:all</span></span></code></pre></div><ul><li><strong>What this does</strong>: Cleans previous builds, compiles TypeScript source modules into JavaScript, builds the browser clean-architecture bundle, and bundles the Preact single-page application (SPA).</li></ul><hr><h2 id="🪟-windows-build-release-commands" tabindex="-1">🪟 Windows Build &amp; Release Commands <a class="header-anchor" href="#🪟-windows-build-release-commands" aria-label="Permalink to &quot;🪟 Windows Build &amp; Release Commands&quot;">​</a></h2><p>Ensure you have run <code>npm run build:all</code> first before executing these.</p><h3 id="_1-package-the-standalone-application-folders" tabindex="-1">1. Package the Standalone Application Folders <a class="header-anchor" href="#_1-package-the-standalone-application-folders" aria-label="Permalink to &quot;1. Package the Standalone Application Folders&quot;">​</a></h3><p>Create the standalone folders containing the executables (<code>.exe</code>) and Electron runtime:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run pack</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">win</span></span></code></pre></div><ul><li><strong>Output Folders</strong>: <ul><li><strong>x64 Build</strong>: [electron/builds/AnimeTV-win32-x64/](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/electron/builds/AnimeTV-win32-x64)</li><li><strong>arm64 Build</strong>: [electron/builds/AnimeTV-win32-arm64/](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/electron/builds/AnimeTV-win32-arm64)</li></ul></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>You can test the application immediately by navigating to the <strong>x64 Build</strong> directory above and double-clicking <code>AnimeTV.exe</code>.</p></div><h3 id="_2-generate-the-windows-installer-exe-setup-wizard" tabindex="-1">2. Generate the Windows Installer (<code>.exe</code> Setup Wizard) <a class="header-anchor" href="#_2-generate-the-windows-installer-exe-setup-wizard" aria-label="Permalink to &quot;2. Generate the Windows Installer (`.exe` Setup Wizard)&quot;">​</a></h3><p>Generate a user-friendly setup installer wizard (<code>animetv-&lt;version&gt;-setup.exe</code>):</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build-win</span></span></code></pre></div><ul><li><strong>What this does</strong>: Runs <code>npm run pack-win</code> first and then uses <code>electron-installer-windows</code> to compile the setup program.</li><li><strong>Output File</strong>: <ul><li><strong>Setup Installer</strong>: [electron/builds/](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/electron/builds/) (e.g., <code>animetv-5.14.6-setup.exe</code>)</li></ul></li></ul><h3 id="_3-create-a-portable-zip-archive" tabindex="-1">3. Create a Portable ZIP Archive <a class="header-anchor" href="#_3-create-a-portable-zip-archive" aria-label="Permalink to &quot;3. Create a Portable ZIP Archive&quot;">​</a></h3><p>To package the standalone <code>x64</code> directory into a portable <code>.zip</code> archive:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run zip</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">win</span></span></code></pre></div><ul><li><strong>Output File</strong>: <ul><li><strong>Portable ZIP</strong>: [electron/builds/AnimeTV-win32-x64-portable.zip](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/electron/builds/AnimeTV-win32-x64-portable.zip)</li></ul></li></ul><hr><h2 id="🤖-android-apk-build-testing-commands" tabindex="-1">🤖 Android APK Build &amp; Testing Commands <a class="header-anchor" href="#🤖-android-apk-build-testing-commands" aria-label="Permalink to &quot;🤖 Android APK Build &amp; Testing Commands&quot;">​</a></h2><p>Ensure your frontend assets are compiled (<code>npm run build:all</code>) before building Android packages.</p><h3 id="_1-build-a-debug-apk-for-local-testing" tabindex="-1">1. Build a Debug APK (For Local Testing) <a class="header-anchor" href="#_1-build-a-debug-apk-for-local-testing" aria-label="Permalink to &quot;1. Build a Debug APK (For Local Testing)&quot;">​</a></h3><p>Use this command to compile an APK with debugging enabled:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build-debug</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apk</span></span></code></pre></div><ul><li><strong>Alternative Direct Command</strong>: <code>.\\gradlew.bat assembleDebug</code></li><li><strong>Output File</strong>: <ul><li><strong>Debug APK</strong>: Check [app/build/outputs/apk/debug/](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/app/build/outputs/apk/debug) for the compiled <code>.apk</code>.</li></ul></li></ul><h3 id="_2-build-a-release-apk-for-distribution" tabindex="-1">2. Build a Release APK (For Distribution) <a class="header-anchor" href="#_2-build-a-release-apk-for-distribution" aria-label="Permalink to &quot;2. Build a Release APK (For Distribution)&quot;">​</a></h3><p>Use this command to compile an optimized release APK:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build-release</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apk</span></span></code></pre></div><ul><li><strong>Alternative Direct Command</strong>: <code>.\\gradlew.bat assembleRelease</code></li><li><strong>Output File</strong>: <ul><li><strong>Release APK</strong>: Check [app/build/outputs/apk/release/](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/app/build/outputs/apk/release) for the compiled <code>.apk</code>.</li></ul></li></ul><h3 id="_3-install-test-the-apk-on-a-connected-device" tabindex="-1">3. Install &amp; Test the APK on a Connected Device <a class="header-anchor" href="#_3-install-test-the-apk-on-a-connected-device" aria-label="Permalink to &quot;3. Install &amp; Test the APK on a Connected Device&quot;">​</a></h3><p>If you have a physical Android TV, phone, or emulator connected via ADB:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb devices</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">adb install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r app</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">outputs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apk</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">debug</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">debug.apk</span></span></code></pre></div><ul><li><strong>Note</strong>: Replace <code>app-debug.apk</code> with the exact filename of the generated APK inside the output directory.</li></ul><hr><h2 id="⚡-quick-reference-cheat-sheet" tabindex="-1">⚡ Quick Reference Cheat Sheet <a class="header-anchor" href="#⚡-quick-reference-cheat-sheet" aria-label="Permalink to &quot;⚡ Quick Reference Cheat Sheet&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Platform</th><th style="text-align:left;">Command</th><th style="text-align:left;">Action</th><th style="text-align:left;">Primary Output</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;"><code>npm run build:all</code></td><td style="text-align:left;">Compiles UI/TypeScript code</td><td style="text-align:left;"><code>app/src/main/assets/view/*</code></td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>npm run pack-win</code></td><td style="text-align:left;">Generates standalone x64 and ARM64 folders</td><td style="text-align:left;"><code>electron/builds/AnimeTV-win32-*/</code></td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>npm run build-win</code></td><td style="text-align:left;">Creates Setup Installer</td><td style="text-align:left;"><code>electron/builds/animetv-&lt;version&gt;-setup.exe</code></td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>npm run zip-win</code></td><td style="text-align:left;">Packages x64 standalone into ZIP</td><td style="text-align:left;"><code>electron/builds/AnimeTV-win32-x64-portable.zip</code></td></tr><tr><td style="text-align:left;"><strong>Android</strong></td><td style="text-align:left;"><code>npm run build-debug-apk</code></td><td style="text-align:left;">Builds Debug APK</td><td style="text-align:left;"><code>app/build/outputs/apk/debug/*.apk</code></td></tr><tr><td style="text-align:left;"><strong>Android</strong></td><td style="text-align:left;"><code>npm run build-release-apk</code></td><td style="text-align:left;">Builds Release APK</td><td style="text-align:left;"><code>app/build/outputs/apk/release/*.apk</code></td></tr></tbody></table><hr><h2 id="🔍-troubleshooting-notes" tabindex="-1">🔍 Troubleshooting &amp; Notes <a class="header-anchor" href="#🔍-troubleshooting-notes" aria-label="Permalink to &quot;🔍 Troubleshooting &amp; Notes&quot;">​</a></h2><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><ul><li><strong>Version Syncing</strong>: The desktop and Android build scripts sync their versions from [app/build.gradle](file:///c:/Users/dhull/OneDrive/Documents/GitHub/AnimeTV/app/build.gradle). Edit <code>versionName</code> and <code>versionCode</code> in that file to bump the versions.</li><li><strong>Code Signing</strong>: The <code>assembleRelease</code> Gradle task currently uses the debug signing config from <code>app/build.gradle</code>. For public store releases, a developer should sign the APK using a secure production release keystore.</li></ul></div>',54)])])}const g=t(l,[["render",n]]);export{c as __pageData,g as default};
